import com.zeeb.luna.domain.model.MediaItem
import com.zeeb.luna.util.FormatUtil

@OptIn(ExperimentalSharedTransitionApi::class, androidx.compose.foundation.ExperimentalFoundationApi::class)
@Composable
fun MediaGridItem(
	    media: MediaItem,
	        isSelected: Boolean,
	            isSelectionMode: Boolean,
	                onLongClick: () -> Unit,
	                    onClick: () -> Unit,
	                        sharedTransitionScope: SharedTransitionScope,
	                            animatedVisibilityScope: AnimatedVisibilityScope
	                            ) {
	                            	    with(sharedTransitionScope) {
	                            	    	        Box(
	                            	    	        	            modifier = Modifier
	                            	    	        	                            .aspectRatio(1f)
	                            	    	        	                                            .padding(1.dp)
	                            	    	        	                                                            .clip(RoundedCornerShape(4.dp))
	                            	    	        	                                                                            .combinedClickable(
	                            	    	        	                                                                            	                    onClick = onClick,
	                            	    	        	                                                                            	                                        onLongClick = onLongClick
	                            	    	        	                                                                            	                                                        )
	                            	    	        	                                                                            	                                                                ) {
	                            	    	        	                                                                            	                                                                	            AsyncImage(
	                            	    	        	                                                                            	                                                                	            	                model = ImageRequest.Builder(LocalContext.current)
	                            	    	        	                                                                            	                                                                	            	                                    .data(media.uri)
	                            	    	        	                                                                            	                                                                	            	                                                        .crossfade(true)
	                            	    	        	                                                                            	                                                                	            	                                                                            .build(),
	                            	    	        	                                                                            	                                                                	            	                                                                                            contentDescription = media.name,
	                            	    	        	                                                                            	                                                                	            	                                                                                                            contentScale = ContentScale.Crop,
	                            	    	        	                                                                            	                                                                	            	                                                                                                                            modifier = Modifier
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                .fillMaxSize()
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    .sharedElement(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                        rememberSharedContentState(key = "media-${media.id}"),
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                animatedVisibilityScope = animatedVisibilityScope
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                    )
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                )

	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                            // Video Duration & Icon
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        if (media.isVideo) {
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                Box(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                    modifier = Modifier
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                            .fillMaxSize()
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    .background(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            Brush.verticalGradient(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                colors = listOf(Color.Transparent, Color.Black.copy(alpha = 0.4f)),
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                startY = 100f
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                            )
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                    )
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                    )
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    Row(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                    modifier = Modifier
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                            .align(Alignment.BottomEnd)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                    .padding(4.dp),
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                        verticalAlignment = Alignment.CenterVertically
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        ) {
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    Text(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                        text = FormatUtil.formatDuration(media.duration),
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                color = Color.White,
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                        fontSize = 10.sp,
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                style = MaterialTheme.typography.labelSmall
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                    )
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                        Spacer(modifier = Modifier.width(2.dp))
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            Icon(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                        Icons.Default.PlayArrow,
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                contentDescription = null,
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                        tint = Color.White,
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                modifier = Modifier.size(12.dp)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                    )
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                    }
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                }

	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                            // Selection Overlay
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        AnimatedVisibility(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                visible = isSelectionMode,
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                enter = fadeIn(),
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                exit = fadeOut()
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            ) {
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                Box(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                    modifier = Modifier
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                            .fillMaxSize()
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                    .background(if (isSelected) Color.Black.copy(alpha = 0.3f) else Color.Transparent)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                            .padding(6.dp)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            ) {
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    if (isSelected) {
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        Icon(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                            imageVector = Icons.Default.CheckCircle,
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                        contentDescription = "Selected",
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                    tint = MaterialTheme.colorScheme.primary,
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                modifier = Modifier
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                .align(Alignment.TopEnd)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                .background(Color.White, CircleShape)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                        )
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            } else {
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        Box(
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                            modifier = Modifier
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                            .size(24.dp)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                            .align(Alignment.TopEnd)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                                                            .background(Color.Black.copy(alpha = 0.2f), CircleShape)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                                                                                            .clip(CircleShape)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                                                                                                                            .background(Color.Transparent)
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                                                                                                                                                    )
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                                                                                                                                                                        }
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                                                                                                                                                                                        }
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                                                                                                                                                                                                    }
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                                                                                                                                                                                                            }
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                                                                                                                                                                                                                }
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        	                                                                                                                                                                                                                                                                                }
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            	                        )
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        	                                                                                                                                                                                                                            }
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    	                        )
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            	                    }
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                	                                                                                                            }
	                            	    	        	                                                                            	                                                                	            	                                                                                                                                                                    	                                                                                                        	                	                                                                    	                            	                                                                                                                                                    	                                                                                                        	                    	                                                                                                                                                            	                                                                                                                                                                        	                                                            	                )
